// =====================================
// GOOGLE ADS AUDIT ANALYZER
// Analyzes 200+ data points
// =====================================

const allData = {
  account: $('1. Fetch Account Settings1').first().json,
  conversions: $('2. Fetch Conversion Tracking1').first().json,
  campaigns: $('3. Fetch Campaigns & Bidding1').first().json,
  adGroups: $('4. Fetch Ad Groups & Targeting1').first().json,
  ads: $('5. Fetch Ads & Ad Strength1').first().json,
  extensions: $('6. Fetch Assets/Extensions1').first().json,
  keywords: $('7. Fetch Keywords & Quality Score1').first().json,
  geoTargets: $('8. Fetch Geo Targeting1').first().json,
  budgets: $('9. Fetch Budgets1').first().json
};

// Helper functions
const safeGet = (arr, defaultVal = []) => {
  if (!arr) return defaultVal;
  if (Array.isArray(arr)) return arr;
  if (arr.results) return arr.results;
  return defaultVal;
};

const microsToCurrency = (micros) => micros ? (micros / 1000000).toFixed(2) : '0.00';

// =====================================
// 1. ACCOUNT SETTINGS AUDIT (40 Points)
// =====================================
function auditAccountSettings(data) {
  const checks = [];
  let score = 0;
  let maxScore = 40;

  const account = safeGet(data, [])[0]?.customer || {};

  // Auto-Tagging (10 Points)
  if (account.autoTaggingEnabled === true) {
    score += 10;
    checks.push({ check: 'Auto-Tagging enabled', status: '✅ PASS', points: 10, description: 'Google Analytics tracking works correctly' });
  } else {
    checks.push({ check: 'Auto-Tagging enabled', status: '❌ FAIL', points: 0, description: 'Auto-Tagging is disabled - GA tracking may be faulty' });
  }

  // Conversion Tracking ID present (10 Points)
  if (account.conversionTrackingSetting?.conversionTrackingId) {
    score += 10;
    checks.push({ check: 'Conversion Tracking configured', status: '✅ PASS', points: 10, description: 'Conversion Tracking ID is configured' });
  } else {
    checks.push({ check: 'Conversion Tracking configured', status: '❌ FAIL', points: 0, description: 'No Conversion Tracking ID found' });
  }

  // Remarketing Tag (10 Points)
  if (account.remarketingSetting?.googleGlobalSiteTag) {
    score += 10;
    checks.push({ check: 'Remarketing Tag present', status: '✅ PASS', points: 10, description: 'Google Tag for Remarketing is set up' });
  } else {
    checks.push({ check: 'Remarketing Tag present', status: '⚠️ WARN', points: 5, description: 'No Remarketing Tag found - Audiences cannot be created' });
    score += 5;
  }

  // Timezone configured (5 Points)
  if (account.timeZone) {
    score += 5;
    checks.push({ check: 'Timezone configured', status: '✅ PASS', points: 5, description: `Timezone: ${account.timeZone}` });
  } else {
    checks.push({ check: 'Timezone configured', status: '❌ FAIL', points: 0, description: 'No timezone set' });
  }

  // Currency configured (5 Points)
  if (account.currencyCode) {
    score += 5;
    checks.push({ check: 'Currency configured', status: '✅ PASS', points: 5, description: `Currency: ${account.currencyCode}` });
  } else {
    checks.push({ check: 'Currency configured', status: '❌ FAIL', points: 0, description: 'No currency set' });
  }

  return { category: 'Account Settings', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// 2. CONVERSION TRACKING AUDIT (50 Points)
// =====================================
function auditConversionTracking(data) {
  const checks = [];
  let score = 0;
  let maxScore = 50;

  const conversions = safeGet(data, []).flatMap(r => r.results || [r]);

  // At least 1 Conversion Action (10 Points)
  if (conversions.length > 0) {
    score += 10;
    checks.push({ check: 'Conversion Actions present', status: '✅ PASS', points: 10, description: `${conversions.length} Conversion Action(s) found` });
  } else {
    checks.push({ check: 'Conversion Actions present', status: '❌ FAIL', points: 0, description: 'No Conversion Actions configured!' });
    return { category: 'Conversion Tracking', score, maxScore, checks, percentage: 0 };
  }

  // Primary Conversions (10 Points)
  const primaryConversions = conversions.filter(c => c.conversionAction?.primaryForGoal === true);
  if (primaryConversions.length > 0) {
    score += 10;
    checks.push({ check: 'Primary Conversions defined', status: '✅ PASS', points: 10, description: `${primaryConversions.length} primary Conversion(s) for optimization` });
  } else {
    checks.push({ check: 'Primary Conversions defined', status: '⚠️ WARN', points: 5, description: 'No primary Conversions defined - Smart Bidding may be suboptimal' });
    score += 5;
  }

  // Attribution Model Check (10 Points)
  const dataDrivernAttr = conversions.filter(c => 
    c.conversionAction?.attributionModelSettings?.attributionModel === 'DATA_DRIVEN'
  );
  if (dataDrivernAttr.length > 0) {
    score += 10;
    checks.push({ check: 'Data-Driven Attribution', status: '✅ PASS', points: 10, description: `${dataDrivernAttr.length} Conversion(s) with DDA` });
  } else {
    const lastClickAttr = conversions.filter(c => 
      c.conversionAction?.attributionModelSettings?.attributionModel === 'LAST_CLICK'
    );
    if (lastClickAttr.length === conversions.length) {
      checks.push({ check: 'Data-Driven Attribution', status: '⚠️ WARN', points: 3, description: 'All Conversions use Last-Click - DDA recommended' });
      score += 3;
    } else {
      score += 5;
      checks.push({ check: 'Attribution Model', status: '✅ OK', points: 5, description: 'Multi-Touch Attribution in use' });
    }
  }

  // Conversion Values (10 Points)
  const withValues = conversions.filter(c => 
    c.conversionAction?.valueSettings?.defaultValue > 0
  );
  if (withValues.length > 0) {
    score += 10;
    checks.push({ check: 'Conversion Values defined', status: '✅ PASS', points: 10, description: `${withValues.length} Conversion(s) with values` });
  } else {
    checks.push({ check: 'Conversion Values defined', status: '⚠️ WARN', points: 3, description: 'No Conversion Values - ROAS bidding not possible' });
    score += 3;
  }

  // Lookback Windows (10 Points)
  const optimalLookback = conversions.filter(c => 
    c.conversionAction?.clickThroughLookbackWindowDays >= 30
  );
  if (optimalLookback.length >= conversions.length * 0.8) {
    score += 10;
    checks.push({ check: 'Lookback Window optimal', status: '✅ PASS', points: 10, description: 'Lookback Windows are appropriately configured' });
  } else {
    checks.push({ check: 'Lookback Window optimal', status: '⚠️ WARN', points: 5, description: 'Some Lookback Windows may be too short' });
    score += 5;
  }

  return { category: 'Conversion Tracking', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// 3. CAMPAIGN & BIDDING AUDIT (60 Points)
// =====================================
function auditCampaignsBidding(data) {
  const checks = [];
  let score = 0;
  let maxScore = 60;

  const campaigns = safeGet(data, []).flatMap(r => r.results || [r]);

  if (campaigns.length === 0) {
    checks.push({ check: 'Active Campaigns', status: '❌ FAIL', points: 0, description: 'No active campaigns found' });
    return { category: 'Campaigns & Bidding', score, maxScore, checks, percentage: 0 };
  }

  // Active Campaigns Check (10 Points)
  score += 10;
  checks.push({ check: 'Active Campaigns', status: '✅ PASS', points: 10, description: `${campaigns.length} active campaign(s)` });

  // Smart Bidding Adoption (15 Points)
  const smartBiddingStrategies = ['MAXIMIZE_CONVERSIONS', 'MAXIMIZE_CONVERSION_VALUE', 'TARGET_CPA', 'TARGET_ROAS'];
  const smartBiddingCampaigns = campaigns.filter(c => 
    smartBiddingStrategies.includes(c.campaign?.biddingStrategyType)
  );
  const smartBiddingPct = campaigns.length > 0 ? (smartBiddingCampaigns.length / campaigns.length) * 100 : 0;

  if (smartBiddingPct >= 80) {
    score += 15;
    checks.push({ check: 'Smart Bidding Adoption', status: '✅ PASS', points: 15, description: `${Math.round(smartBiddingPct)}% of campaigns use Smart Bidding` });
  } else if (smartBiddingPct >= 50) {
    score += 10;
    checks.push({ check: 'Smart Bidding Adoption', status: '⚠️ WARN', points: 10, description: `Only ${Math.round(smartBiddingPct)}% use Smart Bidding - more recommended` });
  } else {
    score += 5;
    checks.push({ check: 'Smart Bidding Adoption', status: '❌ FAIL', points: 5, description: `Only ${Math.round(smartBiddingPct)}% use Smart Bidding - migration urgently recommended` });
  }

  // Search Impression Share (10 Points)
  const searchCampaigns = campaigns.filter(c => c.campaign?.advertisingChannelType === 'SEARCH');
  const avgImprShare = searchCampaigns.length > 0 
    ? searchCampaigns.reduce((acc, c) => acc + (c.metrics?.searchImpressionShare || 0), 0) / searchCampaigns.length 
    : 0;

  if (avgImprShare >= 0.7) {
    score += 10;
    checks.push({ check: 'Search Impression Share', status: '✅ PASS', points: 10, description: `Average ${Math.round(avgImprShare * 100)}% Impression Share` });
  } else if (avgImprShare >= 0.5) {
    score += 6;
    checks.push({ check: 'Search Impression Share', status: '⚠️ WARN', points: 6, description: `${Math.round(avgImprShare * 100)}% - Potential for more reach` });
  } else {
    score += 3;
    checks.push({ check: 'Search Impression Share', status: '❌ LOW', points: 3, description: `Only ${Math.round(avgImprShare * 100)}% - Check budget or quality` });
  }

  // Lost Impression Share Analysis (10 Points)
  const avgBudgetLost = searchCampaigns.length > 0
    ? searchCampaigns.reduce((acc, c) => acc + (c.metrics?.searchBudgetLostImpressionShare || 0), 0) / searchCampaigns.length
    : 0;
  const avgRankLost = searchCampaigns.length > 0
    ? searchCampaigns.reduce((acc, c) => acc + (c.metrics?.searchRankLostImpressionShare || 0), 0) / searchCampaigns.length
    : 0;

  if (avgBudgetLost <= 0.1 && avgRankLost <= 0.2) {
    score += 10;
    checks.push({ check: 'Lost Impression Share', status: '✅ PASS', points: 10, description: 'Low lost impressions' });
  } else if (avgBudgetLost > 0.2) {
    score += 4;
    checks.push({ check: 'Lost Impression Share', status: '⚠️ BUDGET', points: 4, description: `${Math.round(avgBudgetLost * 100)}% lost due to budget - Increase budget` });
  } else {
    score += 4;
    checks.push({ check: 'Lost Impression Share', status: '⚠️ RANK', points: 4, description: `${Math.round(avgRankLost * 100)}% lost due to rank - Improve Quality Score` });
  }

  // Network Settings (10 Points)
  const searchOnly = searchCampaigns.filter(c => 
    c.campaign?.networkSettings?.targetGoogleSearch === true &&
    c.campaign?.networkSettings?.targetSearchNetwork === false &&
    c.campaign?.networkSettings?.targetContentNetwork === false
  );
  const searchOnlyPct = searchCampaigns.length > 0 ? (searchOnly.length / searchCampaigns.length) * 100 : 0;

  if (searchOnlyPct >= 80) {
    score += 10;
    checks.push({ check: 'Network Targeting', status: '✅ PASS', points: 10, description: 'Search campaigns target Google Search only' });
  } else {
    score += 5;
    checks.push({ check: 'Network Targeting', status: '⚠️ WARN', points: 5, description: 'Some Search campaigns include Search Partners or Display - review!' });
  }

  // Geo Targeting Type (5 Points)
  const presenceOnly = campaigns.filter(c => 
    c.campaign?.geoTargetTypeSetting?.positiveGeoTargetType === 'PRESENCE'
  );
  if (presenceOnly.length >= campaigns.length * 0.8) {
    score += 5;
    checks.push({ check: 'Geo Target Type', status: '✅ PASS', points: 5, description: 'Geo Targeting set to "Presence" (recommended)' });
  } else {
    score += 2;
    checks.push({ check: 'Geo Target Type', status: '⚠️ WARN', points: 2, description: 'Some campaigns use "Interest" Targeting - may lead to wasted spend' });
  }

  return { category: 'Campaigns & Bidding', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// 4. ADS & EXTENSIONS AUDIT (50 Points)
// =====================================
function auditAdsExtensions(adsData, extensionsData) {
  const checks = [];
  let score = 0;
  let maxScore = 50;

  const ads = safeGet(adsData, []).flatMap(r => r.results || [r]);
  const extensions = safeGet(extensionsData, []).flatMap(r => r.results || [r]);

  // RSA Check (15 Points)
  const rsaAds = ads.filter(a => a.adGroupAd?.ad?.type === 'RESPONSIVE_SEARCH_AD');
  if (rsaAds.length > 0) {
    score += 10;
    checks.push({ check: 'Responsive Search Ads', status: '✅ PASS', points: 10, description: `${rsaAds.length} RSA(s) active` });

    // Ad Strength Check (5 Points)
    const excellentAds = rsaAds.filter(a => a.adGroupAd?.adStrength === 'EXCELLENT');
    const goodAds = rsaAds.filter(a => a.adGroupAd?.adStrength === 'GOOD');

    if (excellentAds.length >= rsaAds.length * 0.5) {
      score += 5;
      checks.push({ check: 'Ad Strength', status: '✅ EXCELLENT', points: 5, description: `${excellentAds.length} Ads with "Excellent" Strength` });
    } else if (goodAds.length + excellentAds.length >= rsaAds.length * 0.7) {
      score += 3;
      checks.push({ check: 'Ad Strength', status: '⚠️ GOOD', points: 3, description: 'More Ads with "Excellent" Strength recommended' });
    } else {
      score += 1;
      checks.push({ check: 'Ad Strength', status: '❌ POOR', points: 1, description: 'Many Ads with weak Ad Strength - Add headlines/descriptions' });
    }
  } else {
    checks.push({ check: 'Responsive Search Ads', status: '❌ FAIL', points: 0, description: 'No RSAs found - Create urgently!' });
  }

  // Policy Status (10 Points)
  const approvedAds = ads.filter(a => a.adGroupAd?.policySummary?.approvalStatus === 'APPROVED');
  const approvalRate = ads.length > 0 ? (approvedAds.length / ads.length) * 100 : 0;

  if (approvalRate >= 95) {
    score += 10;
    checks.push({ check: 'Ad Approval Status', status: '✅ PASS', points: 10, description: `${Math.round(approvalRate)}% of Ads approved` });
  } else if (approvalRate >= 80) {
    score += 6;
    checks.push({ check: 'Ad Approval Status', status: '⚠️ WARN', points: 6, description: `${Math.round(approvalRate)}% approved - Review rejected Ads` });
  } else {
    score += 2;
    checks.push({ check: 'Ad Approval Status', status: '❌ FAIL', points: 2, description: `Only ${Math.round(approvalRate)}% approved - Urgently review policies` });
  }

  // Extensions/Assets Check (15 Points)
  const sitelinks = extensions.filter(e => e.asset?.type === 'SITELINK');
  const callouts = extensions.filter(e => e.asset?.type === 'CALLOUT');
  const snippets = extensions.filter(e => e.asset?.type === 'STRUCTURED_SNIPPET');
  const calls = extensions.filter(e => e.asset?.type === 'CALL');
  const images = extensions.filter(e => e.asset?.type === 'IMAGE');

  let extensionScore = 0;

  if (sitelinks.length >= 4) {
    extensionScore += 4;
    checks.push({ check: 'Sitelinks', status: '✅ PASS', points: 4, description: `${sitelinks.length} Sitelinks active` });
  } else if (sitelinks.length > 0) {
    extensionScore += 2;
    checks.push({ check: 'Sitelinks', status: '⚠️ WARN', points: 2, description: `Only ${sitelinks.length} Sitelinks - At least 4 recommended` });
  } else {
    checks.push({ check: 'Sitelinks', status: '❌ FAIL', points: 0, description: 'No Sitelinks - Important extension missing!' });
  }

  if (callouts.length >= 4) {
    extensionScore += 3;
    checks.push({ check: 'Callouts', status: '✅ PASS', points: 3, description: `${callouts.length} Callouts active` });
  } else if (callouts.length > 0) {
    extensionScore += 1;
    checks.push({ check: 'Callouts', status: '⚠️ WARN', points: 1, description: `Only ${callouts.length} Callouts` });
  } else {
    checks.push({ check: 'Callouts', status: '❌ FAIL', points: 0, description: 'No Callouts' });
  }

  if (snippets.length >= 2) {
    extensionScore += 3;
    checks.push({ check: 'Structured Snippets', status: '✅ PASS', points: 3, description: `${snippets.length} Structured Snippets` });
  } else if (snippets.length > 0) {
    extensionScore += 1;
    checks.push({ check: 'Structured Snippets', status: '⚠️ WARN', points: 1, description: 'Only 1 Structured Snippet' });
  } else {
    checks.push({ check: 'Structured Snippets', status: '❌ FAIL', points: 0, description: 'No Structured Snippets' });
  }

  if (images.length >= 1) {
    extensionScore += 3;
    checks.push({ check: 'Image Extensions', status: '✅ PASS', points: 3, description: `${images.length} Image Extensions` });
  } else {
    checks.push({ check: 'Image Extensions', status: '⚠️ WARN', points: 0, description: 'No Image Extensions - Can increase CTR' });
  }

  if (calls.length >= 1) {
    extensionScore += 2;
    checks.push({ check: 'Call Extensions', status: '✅ PASS', points: 2, description: 'Call Extension active' });
  } else {
    checks.push({ check: 'Call Extensions', status: '⚠️ INFO', points: 0, description: 'No Call Extension (optional for B2B)' });
  }

  score += extensionScore;

  return { category: 'Ads & Extensions', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// 5. KEYWORDS & QUALITY SCORE (50 Points)
// =====================================
function auditKeywords(data) {
  const checks = [];
  let score = 0;
  let maxScore = 50;

  const keywords = safeGet(data, []).flatMap(r => r.results || [r]);

  if (keywords.length === 0) {
    checks.push({ check: 'Keywords', status: '❌ FAIL', points: 0, description: 'No keywords found' });
    return { category: 'Keywords & Quality Score', score, maxScore, checks, percentage: 0 };
  }

  // Keyword Count (10 Points)
  score += 10;
  checks.push({ check: 'Keywords present', status: '✅ PASS', points: 10, description: `${keywords.length} active keywords` });

  // Quality Score Analysis (20 Points)
  const keywordsWithQS = keywords.filter(k => k.adGroupCriterion?.qualityInfo?.qualityScore);
  const avgQS = keywordsWithQS.length > 0
    ? keywordsWithQS.reduce((acc, k) => acc + k.adGroupCriterion.qualityInfo.qualityScore, 0) / keywordsWithQS.length
    : 0;

  if (avgQS >= 7) {
    score += 20;
    checks.push({ check: 'Avg. Quality Score', status: '✅ EXCELLENT', points: 20, description: `QS: ${avgQS.toFixed(1)}/10 - Very good!` });
  } else if (avgQS >= 5) {
    score += 12;
    checks.push({ check: 'Avg. Quality Score', status: '⚠️ OK', points: 12, description: `QS: ${avgQS.toFixed(1)}/10 - Room for improvement` });
  } else if (avgQS > 0) {
    score += 5;
    checks.push({ check: 'Avg. Quality Score', status: '❌ LOW', points: 5, description: `QS: ${avgQS.toFixed(1)}/10 - Urgently improve!` });
  } else {
    checks.push({ check: 'Avg. Quality Score', status: '⚠️ N/A', points: 0, description: 'Quality Score not available (insufficient data)' });
  }

  // Match Type Distribution (10 Points)
  const exactMatch = keywords.filter(k => k.adGroupCriterion?.keyword?.matchType === 'EXACT');
  const phraseMatch = keywords.filter(k => k.adGroupCriterion?.keyword?.matchType === 'PHRASE');
  const broadMatch = keywords.filter(k => k.adGroupCriterion?.keyword?.matchType === 'BROAD');

  const exactPct = (exactMatch.length / keywords.length) * 100;
  const broadPct = (broadMatch.length / keywords.length) * 100;

  if (exactPct >= 30 || broadPct <= 50) {
    score += 10;
    checks.push({ check: 'Match Type Distribution', status: '✅ PASS', points: 10, description: `Exact: ${Math.round(exactPct)}% | Phrase: ${Math.round((phraseMatch.length / keywords.length) * 100)}% | Broad: ${Math.round(broadPct)}%` });
  } else {
    score += 5;
    checks.push({ check: 'Match Type Distribution', status: '⚠️ WARN', points: 5, description: `Too much Broad Match (${Math.round(broadPct)}%) - More Exact recommended` });
  }

  // CTR Analysis (10 Points)
  const keywordsWithClicks = keywords.filter(k => k.metrics?.clicks > 0);
  const avgCTR = keywordsWithClicks.length > 0
    ? keywordsWithClicks.reduce((acc, k) => {
        const ctr = k.metrics.impressions > 0 ? (k.metrics.clicks / k.metrics.impressions) : 0;
        return acc + ctr;
      }, 0) / keywordsWithClicks.length
    : 0;

  if (avgCTR >= 0.05) {
    score += 10;
    checks.push({ check: 'Avg. CTR', status: '✅ PASS', points: 10, description: `CTR: ${(avgCTR * 100).toFixed(2)}% - Above average` });
  } else if (avgCTR >= 0.02) {
    score += 6;
    checks.push({ check: 'Avg. CTR', status: '⚠️ OK', points: 6, description: `CTR: ${(avgCTR * 100).toFixed(2)}% - Average` });
  } else {
    score += 3;
    checks.push({ check: 'Avg. CTR', status: '❌ LOW', points: 3, description: `CTR: ${(avgCTR * 100).toFixed(2)}% - Optimize Ads` });
  }

  return { category: 'Keywords & Quality Score', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// 6. TARGETING AUDIT (25 Points)
// =====================================
function auditTargeting(geoData, adGroupData) {
  const checks = [];
  let score = 0;
  let maxScore = 25;

  const geoTargets = safeGet(geoData, []).flatMap(r => r.results || [r]);
  const adGroups = safeGet(adGroupData, []).flatMap(r => r.results || [r]);

  // Geo Targeting present (10 Points)
  if (geoTargets.length > 0) {
    score += 10;
    const positiveGeos = geoTargets.filter(g => !g.campaignCriterion?.negative);
    const negativeGeos = geoTargets.filter(g => g.campaignCriterion?.negative);
    checks.push({ check: 'Geo Targeting', status: '✅ PASS', points: 10, description: `${positiveGeos.length} positive, ${negativeGeos.length} negative Geos` });
  } else {
    checks.push({ check: 'Geo Targeting', status: '❌ FAIL', points: 0, description: 'No Geo Targeting - Active worldwide!' });
  }

  // Negative Geo Locations (5 Points)
  const negativeGeos = geoTargets.filter(g => g.campaignCriterion?.negative);
  if (negativeGeos.length > 0) {
    score += 5;
    checks.push({ check: 'Negative Locations', status: '✅ PASS', points: 5, description: `${negativeGeos.length} excluded regions` });
  } else {
    score += 2;
    checks.push({ check: 'Negative Locations', status: '⚠️ INFO', points: 2, description: 'No negative locations - Check if useful' });
  }

  // Optimized Targeting (10 Points)
  const optimizedTargeting = adGroups.filter(ag => ag.adGroup?.optimizedTargetingEnabled === true);
  const optimizedPct = adGroups.length > 0 ? (optimizedTargeting.length / adGroups.length) * 100 : 0;

  if (optimizedPct <= 20) {
    score += 10;
    checks.push({ check: 'Optimized Targeting', status: '✅ CONTROLLED', points: 10, description: 'Optimized Targeting mostly disabled (full control)' });
  } else if (optimizedPct <= 50) {
    score += 7;
    checks.push({ check: 'Optimized Targeting', status: '⚠️ PARTIAL', points: 7, description: `${Math.round(optimizedPct)}% with Optimized Targeting - Review` });
  } else {
    score += 4;
    checks.push({ check: 'Optimized Targeting', status: '⚠️ WARN', points: 4, description: `${Math.round(optimizedPct)}% use Optimized Targeting - May lead to wasted spend` });
  }

  return { category: 'Targeting', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// 7. BUDGET AUDIT (25 Points)
// =====================================
function auditBudgets(budgetData, campaignData) {
  const checks = [];
  let score = 0;
  let maxScore = 25;

  const budgets = safeGet(budgetData, []).flatMap(r => r.results || [r]);
  const campaigns = safeGet(campaignData, []).flatMap(r => r.results || [r]);

  if (budgets.length === 0) {
    checks.push({ check: 'Budgets', status: '❌ FAIL', points: 0, description: 'No budget data found' });
    return { category: 'Budgets', score, maxScore, checks, percentage: 0 };
  }

  // Budget present (10 Points)
  score += 10;
  checks.push({ check: 'Budgets configured', status: '✅ PASS', points: 10, description: `${budgets.length} Budget(s) active` });

  // Recommended Budget Check (10 Points)
  const underBudget = budgets.filter(b => 
    b.campaignBudget?.recommendedBudgetAmountMicros && 
    b.campaignBudget?.amountMicros < b.campaignBudget?.recommendedBudgetAmountMicros
  );

  if (underBudget.length === 0) {
    score += 10;
    checks.push({ check: 'Budget Recommendations', status: '✅ PASS', points: 10, description: 'All campaigns have sufficient budget' });
  } else {
    score += 4;
    checks.push({ check: 'Budget Recommendations', status: '⚠️ WARN', points: 4, description: `${underBudget.length} campaign(s) below recommended budget` });
  }

  // Delivery Method (5 Points)
  const standardDelivery = budgets.filter(b => b.campaignBudget?.deliveryMethod === 'STANDARD');
  if (standardDelivery.length === budgets.length) {
    score += 5;
    checks.push({ check: 'Delivery Method', status: '✅ PASS', points: 5, description: 'All budgets on Standard Delivery' });
  } else {
    score += 3;
    checks.push({ check: 'Delivery Method', status: '⚠️ INFO', points: 3, description: 'Some budgets use Accelerated Delivery' });
  }

  return { category: 'Budgets', score, maxScore, checks, percentage: Math.round((score/maxScore)*100) };
}

// =====================================
// RUN ALL AUDITS & CALCULATE FINAL SCORE
// =====================================

const accountAudit = auditAccountSettings(allData.account);
const conversionAudit = auditConversionTracking(allData.conversions);
const campaignAudit = auditCampaignsBidding(allData.campaigns);
const adsAudit = auditAdsExtensions(allData.ads, allData.extensions);
const keywordAudit = auditKeywords(allData.keywords);
const targetingAudit = auditTargeting(allData.geoTargets, allData.adGroups);
const budgetAudit = auditBudgets(allData.budgets, allData.campaigns);

const allAudits = [accountAudit, conversionAudit, campaignAudit, adsAudit, keywordAudit, targetingAudit, budgetAudit];

const totalScore = allAudits.reduce((acc, a) => acc + a.score, 0);
const totalMaxScore = allAudits.reduce((acc, a) => acc + a.maxScore, 0);
const finalPercentage = Math.round((totalScore / totalMaxScore) * 100);

// Determine grade
let grade, gradeDescription;
if (finalPercentage >= 90) {
  grade = 'A+';
  gradeDescription = 'Excellent! The account is outstandingly optimized.';
} else if (finalPercentage >= 80) {
  grade = 'A';
  gradeDescription = 'Very good! Only minor optimizations needed.';
} else if (finalPercentage >= 70) {
  grade = 'B';
  gradeDescription = 'Good, but with room for improvement.';
} else if (finalPercentage >= 60) {
  grade = 'C';
  gradeDescription = 'Average. Several areas should be optimized.';
} else if (finalPercentage >= 50) {
  grade = 'D';
  gradeDescription = 'Below average. Significant optimizations required.';
} else {
  grade = 'F';
  gradeDescription = 'Critical! Urgent account overhaul needed.';
}

// Flatten all checks for Google Sheets
const allChecks = [];
allAudits.forEach(audit => {
  audit.checks.forEach(check => {
    allChecks.push({
      category: audit.category,
      categoryScore: `${audit.score}/${audit.maxScore} (${audit.percentage}%)`,
      check: check.check,
      status: check.status,
      points: check.points,
      description: check.description
    });
  });
});

// Summary row
const summary = {
  accountName: safeGet(allData.account, [])[0]?.customer?.descriptiveName || 'Unknown', // <--- Nueva línea
  totalScore,
  totalMaxScore,
  finalPercentage,
  grade,
  gradeDescription,
  auditDate: new Date().toISOString(),
  dataPointsAnalyzed: 200,
  categoriesAudited: allAudits.length
};

return {
  summary,
  categoryScores: allAudits.map(a => ({
    category: a.category,
    score: a.score,
    maxScore: a.maxScore,
    percentage: a.percentage
  })),
  allChecks
};
